func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST requests
	if !ctx.IsPost() {
		writeJSONError(ctx, fasthttp.StatusMethodNotAllowed, "Only POST method is allowed")
		return
	}

	// Parse JSON request body
	var requestBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &requestBody); err != nil {
		writeJSONError(ctx, fasthttp.StatusBadRequest, "Invalid JSON body")
		return
	}

	// Validate URL presence and format
	if requestBody.URL == "" {
		writeJSONError(ctx, fasthttp.StatusBadRequest, "URL field is required")
		return
	}

	parsedURL, err := url.Parse(requestBody.URL)
	if err != nil || parsedURL.Scheme == "" || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		writeJSONError(ctx, fasthttp.StatusBadRequest, "Invalid URL: must use http or https scheme")
		return
	}

	// Configure HTTP client with requirements
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare and execute HTTP request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(requestBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0")

	if err := client.Do(req, resp); err != nil {
		writeJSONError(ctx, fasthttp.StatusInternalServerError, fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		writeJSONError(ctx, fasthttp.StatusInternalServerError, fmt.Sprintf("HTTP error: %d", resp.StatusCode()))
		return
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(resp.Body())

	// Prepare and send JSON response
	result := map[string]string{
		"title":       title,
		"description": description,
	}
	jsonData, err := json.Marshal(result)
	if err != nil {
		writeJSONError(ctx, fasthttp.StatusInternalServerError, "Failed to generate response")
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(jsonData)
}

// extractTitleAndDescription parses HTML to find title and meta description
func extractTitleAndDescription(body []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(body))
	inTitle := false
	titleFound := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			tagName := token.Data // Tokenizer normalizes to lowercase

			if tagName == "title" && !titleFound {
				inTitle = true
			} else if tagName == "meta" {
				var nameVal, propertyVal, contentVal string
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" {
						nameVal = attr.Val
					} else if key == "property" {
						propertyVal = attr.Val
					} else if key == "content" {
						contentVal = attr.Val
					}
				}
				// Prefer standard meta description, fallback to Open Graph
				if strings.ToLower(nameVal) == "description" && description == "" {
					description = contentVal
				} else if strings.ToLower(propertyVal) == "og:description" && description == "" {
					description = contentVal
				}
			}
		case html.TextToken:
			if inTitle && !titleFound {
				text := strings.TrimSpace(tokenizer.Token().Data)
				if text != "" {
					title = text
					titleFound = true
					inTitle = false
				}
			}
		case html.EndTagToken:
			if tokenizer.Token().Data == "title" {
				inTitle = false
			}
		}
	}
}

// writeJSONError sends a standardized JSON error response
func writeJSONError(ctx *fasthttp.RequestCtx, statusCode int, message string) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	resp := map[string]string{"error": message}
	if jsonData, err := json.Marshal(resp); err == nil {
		ctx.Write(jsonData)
	} else {
		// Fallback if marshaling fails (unlikely)
		ctx.Write([]byte(fmt.Sprintf(`{"error": "%s"}`, message)))
	}
}

