// URLPreviewResponse represents the JSON response structure
type URLPreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Precompile regex patterns for efficiency
var (
	titleRegex    = regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	descNameRegex = regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	descOGRegex   = regexp.MustCompile(`(?i)<meta[^>]*property=["']og:description["'][^>]*content=["']([^"']*)["']`)
)

// extractTitle extracts page title from HTML content
func extractTitle(body []byte) string {
	matches := titleRegex.FindSubmatch(body)
	if len(matches) > 1 {
		return string(matches[1])
	}
	return ""
}

// extractDescription extracts meta description (standard or Open Graph)
func extractDescription(body []byte) string {
	// Try standard meta description first
	if matches := descNameRegex.FindSubmatch(body); len(matches) > 1 {
		return string(matches[1])
	}
	// Fallback to Open Graph description
	if matches := descOGRegex.FindSubmatch(body); len(matches) > 1 {
		return string(matches[1])
	}
	return ""
}

// sendJSONResponse marshals response and sets appropriate headers
func sendJSONResponse(ctx *fasthttp.RequestCtx, data URLPreviewResponse) {
	ctx.Response.Header.SetContentType("application/json")
	if jsonBytes, err := json.Marshal(data); err == nil {
