		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error": "Internal server error: failed to marshal response"}`)
	}
}

// FetchURLPreview handles POST requests to fetch URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	respData := URLPreviewResponse{}

	// Validate HTTP method
	if string(ctx.Method()) != fasthttp.MethodPost {
		respData.Error = "Only POST method is allowed"
		sendJSONResponse(ctx, respData)
		return
	}

	// Parse JSON request body
	var requestBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &requestBody); err != nil {
		respData.Error = "Invalid JSON body: " + err.Error()
		sendJSONResponse(ctx, respData)
		return
	}

	// Validate URL presence and format
	if requestBody.URL == "" {
		respData.Error = "URL field is required in JSON body"
		sendJSONResponse(ctx, respData)
		return
	}

	parsedURL, err := url.Parse(requestBody.URL)
	if err != nil {
		respData.Error = "Invalid URL format: " + err.Error()
		sendJSONResponse(ctx, respData)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		respData.Error = "URL scheme must be http or https"
		sendJSONResponse(ctx, respData)
		return
	}

	// Configure client with required settings
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack, // Required by spec
	}

	// Prepare and execute HTTP request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(requestBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0") // Good practice for remote servers

