// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Helper to send standardized JSON error responses
	sendJSONError := func(statusCode int, errMsg string) {
		ctx.SetStatusCode(statusCode)
		ctx.SetContentType("application/json; charset=utf-8")
		resp := PreviewResponse{Error: errMsg}
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Logger().Printf("Failed to encode error response: %v", err)
			ctx.SetStatusCode(fasthttp.StatusInternalServerError)
			ctx.SetContentType("text/plain; charset=utf-8")
			ctx.SetBodyString("Internal Server Error")
		}
	}

	// Only allow POST method
	if !ctx.IsPost() {
		sendJSONError(fasthttp.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendJSONError(fasthttp.StatusBadRequest, "Invalid JSON")
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(fasthttp.StatusBadRequest, "URL is required")
		return
	}

	// Configure HTTP client with strict timeouts
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         8 * time.Second,
		WriteTimeout:        8 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	const maxRedirects = 5
	currentURL := targetURL
	var finalResponse *fasthttp.Response
	var lastErr error

	for redirectCount := 0; redirectCount <= maxRedirects; redirectCount++ {
		// Validate current URL against SSRF constraints BEFORE any network operation
		if err := isURLAllowed(currentURL); err != nil {
			sendJSONError(fasthttp.StatusBadRequest, err.Error())
			return
		}

		reqHTTP := fasthttp.AcquireRequest()
		resHTTP := fasthttp.AcquireResponse()
		reqHTTP.SetRequestURI(currentURL)
		reqHTTP.Header.SetMethod("GET")
		reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

		err := client.Do(reqHTTP, resHTTP)
		fasthttp.ReleaseRequest(reqHTTP)
		if err != nil {
			fasthttp.ReleaseResponse(resHTTP)
			lastErr = err
			break
		}

		statusCode := resHTTP.StatusCode()
		isRedirect := statusCode == fasthttp.StatusMovedPermanently ||
			statusCode == fasthttp.StatusFound ||
			statusCode == fasthttp.StatusSeeOther ||
			statusCode == fasthttp.StatusTemporaryRedirect ||
			statusCode == fasthttp.StatusPermanentRedirect

		if !isRedirect {
			finalResponse = resHTTP
			break
		}

		// Handle redirect
		location := resHTTP.Header.Peek("Location")
		if location == nil {
			finalResponse = resHTTP
			break
		}

		locationStr := string(location)
		nextURL, err := url.Parse(locationStr)
		if err != nil {
			fasthttp.ReleaseResponse(resHTTP)
			sendJSONError(fasthttp.StatusBadGateway, "Invalid redirect URL")
			return
		}

		if !nextURL.IsAbs() {
			baseURL, err := url.Parse(currentURL)
			if err != nil {
				fasthttp.ReleaseResponse(resHTTP)
				sendJSONError(fasthttp.StatusBadGateway, "Invalid base URL for redirect")
				return
			}
			nextURL = baseURL.ResolveReference(nextURL)
		}

		// Prepare for next iteration
		currentURL = nextURL.String()
		fasthttp.ReleaseResponse(resHTTP)
	}

	if finalResponse == nil {
		if lastErr != nil {
			sendJSONError(fasthttp.StatusBadGateway, fmt.Sprintf("Failed to fetch URL: %v", lastErr))
		} else {
			sendJSONError(fasthttp.StatusBadGateway, "Too many redirects")
		}
		return
	}
	defer fasthttp.ReleaseResponse(finalResponse)

	// Validate final response status
	if finalResponse.StatusCode() < fasthttp.StatusOK || finalResponse.StatusCode() >= fasthttp.StatusMultipleChoices {
		sendJSONError(fasthttp.StatusBadGateway, fmt.Sprintf("Unexpected status code: %d", finalResponse.StatusCode()))
		return
	}

	bodyBytes := finalResponse.Body()
	if len(bodyBytes) == 0 {
		sendJSONError(fasthttp.StatusBadGateway, "Empty response body")
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		sendJSONError(fasthttp.StatusInternalServerError, fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		sendJSONError(fasthttp.StatusInternalServerError, "Failed to encode response")
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML content.
func parseHTMLPreview(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string

	// Helper to extract concatenated text content from a node
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result.WriteString(getText(c))
		}
		return result.String()
	}

	// Traverse DOM tree to find title and meta description
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract page title (first occurrence)
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(getText(n))
			}
			// Extract meta description (first valid occurrence)
			if n.Data == "meta" && description == "" {
				var nameVal, contentVal string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						nameVal = attr.Val
					} else if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if strings.EqualFold(nameVal, "description") && contentVal != "" {
					description = strings.TrimSpace(contentVal)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
		}
	}

	visit(doc)
	return title, description, nil
}

