	if err := httpClient.Do(req, resp); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", resp.StatusCode()), fasthttp.StatusInternalServerError)
		return
	}

	title, description := parseHTML(resp.Body())
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	result := map[string]string{
		"title":       title,
		"description": description,
	}

	ctx.SetContentType("application/json")
	if jsonBytes, err := json.Marshal(result); err != nil {
		ctx.Error("Internal server error", fasthttp.StatusInternalServerError)
	} else {
		ctx.SetBody(jsonBytes)
	}
}

func parseHTML(body []byte) (string, string) {
	title := ""
	description := ""
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if title != "" && description != "" {
			return
		}
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
