// parseHTMLPreview extracts title and meta description from HTML content.
// Prefers Open Graph description (og:description) over standard meta description.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	var titleBuilder strings.Builder
	inTitle := false
	titleFound := false
	var ogDesc, stdDesc string

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				goto finalize
			}
			return "", "", z.Err()
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, _ := z.TagName()
			tagStr := string(tagName)

			// Handle title tag (only process start tags, title cannot be self-closing)
			if tt == html.StartTagToken && !titleFound && tagStr == "title" {
				inTitle = true
				titleBuilder.Reset()
				continue
			}

			// Process meta tags for descriptions
			if tagStr == "meta" {
				var propVal, nameVal, contentVal string
				for {
					key, val, more := z.TagAttr()
					keyStr := string(key)
					valStr := string(val)
					switch keyStr {
					case "property":
						propVal = valStr
					case "name":
						nameVal = valStr
					case "content":
						contentVal = valStr
					}
					if !more {
						break
					}
				}

				// Capture first og:description
				if ogDesc == "" && propVal == "og:description" {
					ogDesc = contentVal
				}
				// Capture first standard description (only if og:description not found yet)
				if stdDesc == "" && nameVal == "description" {
					stdDesc = contentVal
				}
			}
		case html.EndTagToken:
			tagName, _ := z.TagName()
			if inTitle && string(tagName) == "title" {
				inTitle = false
				titleFound = true
				title = titleBuilder.String()
			}
		case html.TextToken:
			if inTitle {
				titleBuilder.Write(z.Text())
			}
		}
	}

finalize:
	// Prefer Open Graph description over standard meta description
	if ogDesc != "" {
		description = ogDesc
	} else {
		description = stdDesc
	}

	// Clean up extracted values
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)
	return title, description, nil
}

