		return
	}

	ctx.Response.Header.SetContentType("application/json")
	ctx.Response.SetBody(jsonData)
}

func extractTitleAndDescription(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

