// parseHTMLPreview extracts title and meta description from HTML.
// Prioritizes standard meta description (name="description") over Open Graph (property="og:description").
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Helper to get attribute value (keys are normalized to lowercase by parser)
	getAttr := func(n *html.Node, key string) string {
		for _, attr := range n.Attr {
			if attr.Key == key {
				return attr.Val
			}
		}
		return ""
	}

	// Helper to extract concatenated text content from node subtree
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result string
		for child := n.FirstChild; child != nil; child = child.NextSibling {
			result += getText(child)
		}
		return result
	}

	var candidateStandardDesc string
	var candidateOGDesc string

	// Traverse DOM tree to find title and description candidates
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if title == "" {
					title = getText(n)
				}
			case "meta":
				nameVal := getAttr(n, "name")
				propVal := getAttr(n, "property")
				contentVal := getAttr(n, "content")

				if nameVal == "description" && candidateStandardDesc == "" {
					candidateStandardDesc = contentVal
				}
				if propVal == "og:description" && candidateOGDesc == "" {
					candidateOGDesc = contentVal
				}
			}
		}
		for child := n.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
