	}
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		writeError(ctx, "invalid url format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeError(ctx, "only http and https urls are allowed", fasthttp.StatusBadRequest)
