// isPrivateIP checks if the given IP is in a private/reserved range.
func isPrivateIP(ip net.IP) bool {
	// Convert IPv4-mapped IPv6 addresses to IPv4 representation
	if ipv4 := ip.To4(); ipv4 != nil {
		ip = ipv4
	}
	privateBlocks := []*net.IPNet{
		// IPv4 private networks
		{IP: net.ParseIP("10.0.0.0").To4(), Mask: net.IPv4Mask(255, 0, 0, 0)},
		{IP: net.ParseIP("172.16.0.0").To4(), Mask: net.IPv4Mask(255, 240, 0, 0)},
		{IP: net.ParseIP("192.168.0.0").To4(), Mask: net.IPv4Mask(255, 255, 0, 0)},
		// IPv4 loopback, link-local, and metadata services
		{IP: net.ParseIP("127.0.0.0").To4(), Mask: net.IPv4Mask(255, 0, 0, 0)},
		{IP: net.ParseIP("169.254.0.0").To4(), Mask: net.IPv4Mask(255, 255, 0, 0)}, // Includes AWS metadata 169.254.169.254
		// IPv6 private networks
		{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},       // loopback
		{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)},      // unique local
		{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)},     // link-local
		{IP: net.ParseIP("ff00::"), Mask: net.CIDRMask(8, 128)},      // multicast
	}
	for _, block := range privateBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

