// parseHTMLPreview extracts title and meta description from HTML.
// Prefers standard meta description (name="description") over Open Graph description (property="og:description").
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Helper to extract text content from a node subtree
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result string
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result += getText(c)
		}
		return result
	}

	var standardDesc, ogDesc string
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract first title tag content
			if n.Data == "title" && title == "" {
				title = getText(n)
			}

			// Process meta tags only if we haven't found required descriptions yet
			if n.Data == "meta" {
				// Check for standard meta description (name="description")
				if standardDesc == "" {
					var contentVal string
					hasNameDesc := false
					for _, attr := range n.Attr {
						if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
							hasNameDesc = true
						}
						if attr.Key == "content" {
							contentVal = attr.Val
						}
					}
					if hasNameDesc && contentVal != "" {
						standardDesc = contentVal
					}
				}

				// Check for Open Graph description (property="og:description") if not found yet
				if ogDesc == "" {
					var contentVal string
					hasOgDesc := false
					for _, attr := range n.Attr {
						if attr.Key == "property" && strings.EqualFold(attr.Val, "og:description") {
							hasOgDesc = true
						}
						if attr.Key == "content" {
							contentVal = attr.Val
						}
					}
					if hasOgDesc && contentVal != "" {
						ogDesc = contentVal
					}
				}
			}
		}

		// Continue traversal to children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
		}
	}

	visit(doc)

	title = strings.TrimSpace(title)
	// Prefer standard description over Open Graph description
	if standardDesc != "" {
		description = strings.TrimSpace(standardDesc)
	} else {
		description = strings.TrimSpace(ogDesc)
	}

	return title, description, nil
}

