	"golang.org/x/net/html"
)

var httpClient = &fasthttp.Client{
	Dial:               fasthttp.DialDualStack,
	ReadTimeout:        3 * time.Second,
	WriteTimeout:       3 * time.Second,
	MaxResponseBodySize: 10 * 1024 * 1024, // 10MB limit
}

func extractMetadata(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = getText(n)
			}
			if n.Data == "meta" && description == "" {
				var nameVal, contentVal string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						nameVal = attr.Val
					} else if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if nameVal == "description" && contentVal != "" {
					description = contentVal
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests (routing handled in main)
	if !ctx.IsPost() {
		ctx.Error("Method Not Allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var reqBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "invalid JSON body"})
		return
	}

	// Validate URL presence and format
	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "url field is required"})
		return
	}

	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "invalid URL format or unsupported scheme (must be http/https)"})
		return
	}

	// Prepare HTTP request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("Mozilla/5.0 (URLPreviewBot; +https://example.com)")

	// Execute request with redirect handling (client uses default redirect behavior)
	if err := httpClient.Do(req, resp); err != nil {
		status := fasthttp.StatusGatewayTimeout
		if err == fasthttp.ErrTimeout {
			status = fasthttp.StatusRequestTimeout
		}
		ctx.SetStatusCode(status)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "failed to fetch URL: " + err.Error()})
		return
	}

	// Check HTTP status
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": fmt.Sprintf("remote server returned status %d", resp.StatusCode())})
		return
	}

	// Extract metadata from HTML
	title, description := extractMetadata(resp.Body())

	// Return JSON response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	response := map[string]string{
		"title":       title,
		"description": description,
	}
	if err := json.NewEncoder(ctx).Encode(response); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "failed to encode response"})
	}
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		if string(ctx.Path()) == "/preview" {
			FetchURLPreview(ctx)
			return
		}
		ctx.Error("Not Found", fasthttp.StatusNotFound)
	}

	fmt.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		panic(err)
	}
}

