	}

	// Configure client with required settings
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack, // Required by spec
		MaxRedirectsCount:   10,                      // Maximum number of redirects to follow
		ReadTimeout:         15 * time.Second,
		WriteTimeout:        15 * time.Second,
		MaxResponseBodySize: 10 * 1024 * 1024, // 10MB limit
	}

