	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetBody(jsonResp)
}

// extractMetadata parses HTML to extract title and description
func extractMetadata(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var title, description string
	var crawler func(*html.Node)
	crawler = func(n *html.Node) {
		// Stop early if both values found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title text
			if n.Data == "title" && title == "" {
				title = getText(n)
				return
			}

			// Extract description from meta tags
			if n.Data == "meta" && description == "" {
				nameAttr := getAttr(n, "name")
				propAttr := getAttr(n, "property")
				contentAttr := getAttr(n, "content")

				if contentAttr != "" {
					if nameAttr == "description" || propAttr == "og:description" {
						description = contentAttr
					}
				}
			}
		}

		// Recurse through children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
			if title != "" && description != "" {
				return
			}
		}
	}
	crawler(doc)
	return title, description
}

// getText recursively collects text content from node
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result.WriteString(getText(c))
	}
	return result.String()
}

// getAttr retrieves attribute value by key
func getAttr(n *html.Node, key string) string {
	for _, attr := range n.Attr {
		if attr.Key == key {
			return attr.Val
		}
	}
	return ""
}

