	// SSRF protection: Validate host to block internal resources
	host := parsedURL.Hostname()
	if host == "" {
		ctx.Error("Invalid host in URL", fasthttp.StatusBadRequest)
		return
	}

	// Block localhost by name (case-insensitive)
	if strings.EqualFold(host, "localhost") {
		ctx.Error("Access to localhost is forbidden", fasthttp.StatusBadRequest)
		return
	}

