// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Helper to extract text content from a node subtree
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result string
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result += getText(c)
		}
		return result
	}

	// Traverse DOM to find title and description
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		// Stop early if both values found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract page title (first <title> tag)
			if title == "" && n.Data == "title" {
				title = strings.TrimSpace(getText(n))
				return // Title found, no need to traverse children
