func extractTitle(body []byte) string {
	matches := titleRegex.FindSubmatch(body)
	if len(matches) > 1 {
		return html.UnescapeString(strings.TrimSpace(string(matches[1])))
	}
	return ""
}

// extractDescription extracts meta description from HTML body using regex
func extractDescription(body []byte) string {
