// FetchURLPreview handles POST requests to fetch URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if string(ctx.Method()) != fasthttp.MethodPost {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	type RequestBody struct {
		URL string `json:"url"`
	}
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.Error("Invalid JSON payload", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence and scheme
	if reqBody.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.Error("Invalid URL format or unsupported scheme (only http/https allowed)", fasthttp.StatusBadRequest)
		return
	}

	// Prepare HTTP request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0")

