	}
	if !strings.HasPrefix(input.URL, "http://") && !strings.HasPrefix(input.URL, "https://") {
		ctx.Error("URL must use http:// or https:// scheme", fasthttp.StatusBadRequest)
		return
	}

	// Configure client with required settings
	client := &fasthttp.Client{
		Dial:                   fasthttp.DialDualStack,
		MaxRedirectCount:       10, // Fixed field name: MaxRedirects -> MaxRedirectCount
		ReadTimeout:            10 * time.Second,
		WriteTimeout:           10 * time.Second,
		MaxResponseBodySize:    10 * 1024 * 1024, // 10MB limit
