	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(input.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Execute request with redirect handling (via MaxRedirectCount + Do)
	if err := client.Do(req, resp); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Check HTTP status
	if resp.StatusCode() < 200 || resp.StatusCode() >= 300 {
		ctx.Error(fmt.Sprintf("Received non-2xx status: %d", resp.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML content
	title, description := parseHTML(resp.Body())

	// Prepare JSON response
	result := map[string]string{
		"title":       title,
		"description": description,
	}

	if jsonBytes, err := json.Marshal(result); err != nil {
