					}
					titleBuilder.WriteString(text)
				}
			}
		case html.EndTagToken:
			if token := z.Token(); strings.ToLower(token.Data) == "title" {
				inTitle = false
				if !titleFound && titleBuilder.Len() > 0 {
					titleFound = true
				}
			}
