// isUnsafeHost checks if host is localhost, loopback, private IP range, or resolves to unsafe IPs
func isUnsafeHost(host string) bool {
	// Block localhost string explicitly
	if strings.EqualFold(host, "localhost") {
		return true
	}

	// Check if host is a literal IP address
	ip := net.ParseIP(host)
	if ip != nil {
		return ip.IsLoopback() || isPrivateIP(ip)
	}

	// Resolve domain names with timeout to prevent SSRF via DNS rebinding/private IPs
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		// Block on DNS failure to prevent potential SSRF bypass
		return true
	}

	// Block if ANY resolved IP is unsafe
	for _, ipAddr := range ips {
		if ipAddr.IP.IsLoopback() || isPrivateIP(ipAddr.IP) {
			return true
		}
	}

	return false
}

// isPrivateIP checks for RFC-defined private and link-local IP ranges
func isPrivateIP(ip net.IP) bool {
	if ipv4 := ip.To4(); ipv4 != nil {
		switch {
		case ipv4[0] == 10: // 10.0.0.0/8
			return true
		case ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31: // 172.16.0.0/12
			return true
		case ipv4[0] == 192 && ipv4[1] == 168: // 192.168.0.0/16
			return true
		case ipv4[0] == 169 && ipv4[1] == 254: // 169.254.0.0/16 (link-local)
			return true
		}
		return false
	}

	// IPv6 checks
	ip = ip.To16()
	if ip == nil {
		return false
	}

	// fc00::/7 (unique local addresses)
	if ip[0] == 0xfc || ip[0] == 0xfd {
		return true
	}

	// fe80::/10 (link-local)
	if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
		return true
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML content.
func parseHTMLPreview(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		// Stop traversal if both values are already found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title (first occurrence only)
			if n.Data == "title" && title == "" {
				title = getText(n)
				return // No need to traverse title children further in this branch
			}

			// Extract meta description (first valid occurrence only)
			if n.Data == "meta" && description == "" {
				var hasDescription bool
				var contentVal string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						hasDescription = true
					}
					if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if hasDescription && contentVal != "" {
					description = contentVal
				}
				return // Meta tags are self-closing; skip children
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
			// Early termination check after each child
			if title != "" && description != "" {
				return
			}
		}
	}

	visit(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

// getText recursively extracts text content from an HTML node.
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

