// isInternalHost checks if the hostname resolves to internal/reserved addresses
func isInternalHost(host string) bool {
	// Normalize host: remove IPv6 zone identifiers and brackets
	host = strings.ToLower(strings.Trim(host, "[]"))
	if strings.IndexByte(host, '%') > 0 {
		host = host[:strings.IndexByte(host, '%')]
	}

	// Block localhost explicitly
	if host == "localhost" || host == "ip6-localhost" || host == "ip6-loopback" {
		return true
	}

	// Parse as IP address
	ip := net.ParseIP(host)
	if ip == nil {
		return false
	}

	// Block reserved address categories
	if ip.IsLoopback() || 
	   ip.IsPrivate() || 
	   ip.IsLinkLocalUnicast() || 
	   ip.IsLinkLocalMulticast() || 
	   ip.IsUnspecified() {
		return true
	}

	// Block cloud metadata endpoints
	metadataIPs := []string{
		"169.254.169.254", // AWS, Azure, GCP, DigitalOcean
		"169.254.169.253", // Some Azure endpoints
		"100.100.100.200", // Alibaba Cloud
	}
	for _, metaIP := range metadataIPs {
		if ip.Equal(net.ParseIP(metaIP)) {
			return true
		}
	}
	return false
}

