	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendJSONError("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendJSONError("URL must use http or https scheme", fasthttp.StatusBadRequest)
