// parseHTMLPreview extracts title and meta description from HTML content.
// Supports:
//   - <title> tag content (first occurrence)
//   - <meta name="description" content="..."> (priority)
//   - <meta property="og:description" content="..."> (fallback)
func parseHTMLPreview(r io.Reader) (string, string, error) {
	tokenizer := html.NewTokenizer(r)
	var title, description string
	inTitle := false
	titleFound := false
	descFound := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", tokenizer.Err()
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			tagName := strings.ToLower(token.Data)
			if tagName == "title" && !titleFound {
				inTitle = true
			} else if tagName == "meta" && !descFound {
				var contentVal string
				isDescMeta := false
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					if key == "content" {
						contentVal = attr.Val
					} else if key == "name" && strings.ToLower(attr.Val) == "description" {
						isDescMeta = true
					} else if key == "property" && strings.ToLower(attr.Val) == "og:description" {
						isDescMeta = true
					}
				}
				if isDescMeta && contentVal != "" {
					description = contentVal
					descFound = true
				}
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if strings.ToLower(token.Data) == "title" && inTitle {
				inTitle = false
				titleFound = true
			}
		case html.TextToken:
			if inTitle && !titleFound {
				text := strings.TrimSpace(tokenizer.Token().Data)
				if text != "" {
					if title == "" {
						title = text
					} else {
						title += " " + text
					}
				}
			}
		}

		// Early termination optimization
		if titleFound && descFound {
			break
		}
	}

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

