// validateURL checks for SSRF risks and invalid constructs
func validateURL(u *url.URL) error {
	// Block non-http(s) schemes
	if u.Scheme != "http" && u.Scheme != "https" {
		return errors.New("URL must use http or https scheme")
	}

	// Block credentials in URL (prevents auth leakage)
	if u.User != nil {
		return errors.New("URL must not contain credentials")
	}

	// Block reserved hostnames
	lowerHost := strings.ToLower(u.Hostname())
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" || 
	   strings.HasPrefix(lowerHost, "localhost.") || lowerHost == "0.0.0.0" {
		return errors.New("reserved hostname blocked")
	}

	// Block private IPs in host (first layer of defense)
	if isPrivateHost(u.Hostname()) {
		return errors.New("private IP address blocked")
	}

	return nil
}

// isPrivateHost checks if host resolves to private IPs (defense-in-depth)
func isPrivateHost(host string) bool {
	// Check if host is literal IP
	if ip := net.ParseIP(host); ip != nil {
		return isPrivateIP(ip)
	}

	// Resolve domain and check all IPs (with timeout)
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return false // Fail open for DNS errors (client.Dial provides final defense)
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return true
		}
	}
	return false
}

// isPrivateIP checks for SSRF-risk IP ranges (RFC 1918, loopback, link-local, etc.)
func isPrivateIP(ip net.IP) bool {
