	}
	if ip4[0] == 0 { // 0.0.0.0/8
		return true
	}
	return false
}

// isRedirectStatus checks if HTTP status indicates redirect
func isRedirectStatus(code int) bool {
	return code == fasthttp.StatusMovedPermanently ||
