// FetchURLPreview handles POST requests to fetch URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if string(ctx.Method()) != fasthttp.MethodPost {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var requestBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &requestBody); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence and scheme (case-insensitive)
	if requestBody.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}
	lowerURL := strings.ToLower(requestBody.URL)
	if !strings.HasPrefix(lowerURL, "http://") && !strings.HasPrefix(lowerURL, "https://") {
		ctx.Error("URL must start with http:// or https://", fasthttp.StatusBadRequest)
		return
	}

	// Prepare HTTP request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(requestBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0") // Identify requests

	// Create context with timeout for entire operation (including redirects)
	// Derive from request context to cancel if client disconnects
	fetchCtx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	// Fetch URL content with redirect handling using configured client
	err := httpClient.DoRedirectsContext(fetchCtx, req, resp, 5) // Limit redirects to 5
	if err != nil {
		if fetchCtx.Err() == context.DeadlineExceeded {
			ctx.Error("Request timeout exceeded", fasthttp.StatusGatewayTimeout)
		} else {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		}
		return
	}

	// Check HTTP status code
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", resp.StatusCode()), fasthttp.StatusInternalServerError)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Prepare JSON response
	result := map[string]string{
		"title":       strings.TrimSpace(title),
		"description": strings.TrimSpace(description),
	}

	// Send JSON response
	ctx.SetContentType("application/json")
	if jsonData, err := json.Marshal(result); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	} else {
		ctx.SetStatusCode(fasthttp.StatusOK)
		ctx.Write(jsonData)
	}
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body []byte) (string, string) {
	title := ""
	description := ""

	// Parse HTML document
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return title, description
	}

	// Traverse DOM tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop early if both values are already found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title text
			if n.Data == "title" && title == "" {
				title = getText(n)
				return
			}

			// Extract meta description
			if n.Data == "meta" && description == "" {
				hasDescriptionName := false
				var contentVal string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						hasDescriptionName = true
					}
					if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if hasDescriptionName && contentVal != "" {
					description = contentVal
				}
				return
			}
		}

		// Recursively traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
			if title != "" && description != "" {
				break
			}
		}
	}

	traverse(doc)
	return title, description
}

// getText recursively extracts text content from HTML node
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

func main() {
	// Start HTTP server with configured handler
	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(fmt.Sprintf("Server failed: %v", err))
	}
}

