package main

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// isBlockedIP checks if an IP address belongs to restricted ranges
func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	return ip.IsLoopback() || 
	       ip.IsPrivate() || 
	       ip.IsLinkLocalUnicast() || 
	       ip.IsLinkLocalMulticast() || 
	       ip.IsMulticast()
}

// createSafeDialer returns a dialer that blocks connections to restricted IP ranges
func createSafeDialer(dialTimeout time.Duration) fasthttp.DialFunc {
	return func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, fmt.Errorf("invalid address %q: %w", addr, err)
		}

		// Check if host is a literal IP address
		if ip := net.ParseIP(host); ip != nil {
			if isBlockedIP(ip) {
				return nil, fmt.Errorf("access to private or reserved IP addresses is denied")
			}
			return net.DialTimeout("tcp", addr, dialTimeout)
		}

		// Resolve hostname with timeout
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
		if err != nil {
			return nil, fmt.Errorf("DNS resolution failed for %q: %w", host, err)
		}

		// Validate all resolved IPs
		for _, ip := range ips {
			if isBlockedIP(ip) {
				return nil, fmt.Errorf("access to private or reserved IP addresses is denied (resolved to %s)", ip.String())
			}
		}

		// Attempt connection to first valid IP
		if len(ips) == 0 {
			return nil, fmt.Errorf("no IPs resolved for %q", host)
		}

		return net.DialTimeout("tcp", net.JoinHostPort(ips[0].String(), port), dialTimeout)
	}
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		sendJSONError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendJSONError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendJSONError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with SSRF-protected dialer
	client := &fasthttp.Client{
		Dial:                createSafeDialer(10 * time.Second),
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		sendJSONError(ctx, "Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		sendJSONError(ctx, "Unexpected status code from target URL", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendJSONError(ctx, "Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		sendJSONError(ctx, "Failed to parse HTML content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		sendJSONError(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// sendJSONError sends a standardized JSON error response
func sendJSONError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	resp := PreviewResponse{Error: message}
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
// Checks standard meta description first, falls back to Open Graph description.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Helper to extract text content from a node subtree
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result.WriteString(getText(c))
		}
		return result.String()
	}

	// Traverse DOM to find title and description
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title (first occurrence only)
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(getText(n))
			}

			// Extract description from meta tags (first valid match only)
			if n.Data == "meta" && description == "" {
				var nameVal, propVal, contentVal string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						nameVal = strings.ToLower(attr.Val)
					case "property":
						propVal = strings.ToLower(attr.Val)
					case "content":
						contentVal = attr.Val
					}
				}

				// Prefer standard description, fall back to Open Graph
				if (nameVal == "description" || propVal == "og:description") && contentVal != "" {
					description = strings.TrimSpace(contentVal)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
		}
	}

	visit(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

