	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || parsedURL.Scheme == "" || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.Error("Invalid URL format. Must be valid http/https URL", fasthttp.StatusBadRequest)
		return
	}

	// Configure HTTP client with required settings
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         3 * time.Second,
		WriteTimeout:        3 * time.Second,
		MaxIdleConnDuration: 3 * time.Second,
		MaxRedirectsCount:   10, // Follow redirects (maximum 10 redirects)
