	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0 (+https://example.com/bot)")

	// Execute request with redirect handling (via MaxRedirectsCount configuration)
