// extractMetadata parses HTML to find title and meta description
func extractMetadata(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		// Early exit if both values are found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title text
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(getText(n))
				return
			}

			// Extract meta description
			if n.Data == "meta" && description == "" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
