					case "content":
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" && contentAttr != "" {
					description = strings.TrimSpace(contentAttr)
					return
				}
			}
		}

		// Recurse through children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	visit(doc)
	return title, description
}

// getText recursively extracts text content from HTML node
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}

	var result string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result += getText(c)
	}
	return result
}

