var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range []string{
		"0.0.0.0/32",     // IPv4 unspecified
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // IPv4 private
		"172.16.0.0/12",  // IPv4 private
		"192.168.0.0/16", // IPv4 private
		"169.254.0.0/16", // IPv4 link-local
		"::/128",         // IPv6 unspecified
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // IPv6 unique local
		"fe80::/10",      // IPv6 link-local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPBlocks = append(privateIPBlocks, block)
		}
	}
}

func isPrivateIP(ip net.IP) bool {
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and host
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Validate host is not private/reserved
	hostname := parsedURL.Hostname()
	if hostname == "" {
		ctx.Error("Invalid URL: missing host", fasthttp.StatusBadRequest)
		return
	}

	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			ctx.Error("Access to private networks is forbidden", fasthttp.StatusForbidden)
			return
		}
	} else {
		dnsCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
		defer cancel()
		ips, err := net.DefaultResolver.LookupIP(dnsCtx, "ip", hostname)
		if err != nil {
			ctx.Error("Failed to resolve hostname", fasthttp.StatusBadRequest)
			return
		}
		for _, ip := range ips {
			if isPrivateIP(ip) {
				ctx.Error("Access to private networks is forbidden", fasthttp.StatusForbidden)
				return
			}
		}
	}

	// Use fasthttp.Client to fetch with timeout and redirect limits
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	reqHTTP := fasthttp.AcquireRequest()
	resHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(resHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod("GET")
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirects := 10
	if err := client.DoRedirects(reqHTTP, resHTTP, maxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if resHTTP.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", resHTTP.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := resHTTP.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML content.
// Returns trimmed title and description. Description prioritizes:
// 1. <meta name="description" content="...">
// 2. <meta property="og:description" content="...">
func parseHTMLPreview(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title string
	var descStandard, descOG string

	// Helper to get attribute value (keys are normalized to lowercase by parser)
	getAttr := func(n *html.Node, key string) string {
		for _, attr := range n.Attr {
			if attr.Key == key {
				return attr.Val
			}
		}
		return ""
	}

	// Helper to extract all text content from a node subtree
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result.WriteString(getText(c))
		}
		return result.String()
	}

	// Traverse DOM to find title and relevant meta tags
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract first title tag content
			if n.Data == "title" && title == "" {
				title = getText(n)
			}

			// Process meta tags for descriptions
			if n.Data == "meta" {
				// Standard description (only capture first non-empty)
				if descStandard == "" {
					if nameVal := getAttr(n, "name"); strings.EqualFold(nameVal, "description") {
						if contentVal := getAttr(n, "content"); contentVal != "" {
							descStandard = contentVal
						}
					}
				}

				// Open Graph description (only capture first non-empty if standard not found)
				if descOG == "" && descStandard == "" {
					if propVal := getAttr(n, "property"); strings.EqualFold(propVal, "og:description") {
						if contentVal := getAttr(n, "content"); contentVal != "" {
							descOG = contentVal
						}
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	description := descStandard
	if description == "" {
		description = descOG
	}

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

