// safeDial provides SSRF protection by blocking connections to private/internal IP ranges
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address format: %w", err)
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("DNS resolution failed: %w", err)
	}

	// Block request if ANY resolved IP is in a restricted range
	for _, ip := range ips {
		if isBlockedIP(ip) {
			return nil, fmt.Errorf("blocked IP address: %s", ip.String())
		}
	}

	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		DualStack: true,
	}

	var lastErr error
	for _, ip := range ips {
		target := net.JoinHostPort(ip.String(), port)
		conn, err := dialer.Dial("tcp", target)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}
	return nil, fmt.Errorf("connection failed: %w", lastErr)
}

// isBlockedIP checks if an IP belongs to restricted ranges (loopback, private, link-local, etc.)
func isBlockedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	if ip.IsLoopback() {
		return true
	}
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	if ipv4 := ip.To4(); ipv4 != nil {
		// 0.0.0.0
		if ipv4.Equal(net.IPv4zero) {
			return true
		}
		// 10.0.0.0/8
		if ipv4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ipv4[0] == 192 && ipv4[1] == 168 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ipv4[0] == 169 && ipv4[1] == 254 {
			return true
		}
		return false
	}
	// IPv6 unique local addresses (fc00::/7)
	ip16 := ip.To16()
	if ip16 != nil && (ip16[0] == 0xfc || ip16[0] == 0xfd) {
		return true
	}
	return false
}

var httpClient = &fasthttp.Client{
	Dial:           safeDial,
	ReadTimeout:    10 * time.Second,
	WriteTimeout:   10 * time.Second,
	MaxConnsPerHost: 100, // Prevent resource exhaustion
}

func main() {
	log.Fatal(fasthttp.ListenAndServe(":8080", requestHandler))
}

func requestHandler(ctx *fasthttp.RequestCtx) {
	if string(ctx.Path()) == "/preview" && ctx.IsPost() {
		FetchURLPreview(ctx)
		return
	}
	ctx.Error("Not Found", fasthttp.StatusNotFound)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		sendError(ctx, fasthttp.StatusBadRequest, "Invalid JSON body")
		return
	}

	if reqBody.URL == "" {
		sendError(ctx, fasthttp.StatusBadRequest, "URL field is required")
		return
	}

	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		sendError(ctx, fasthttp.StatusBadRequest, "Invalid URL format")
		return
	}
	if parsedURL.Scheme == "" {
		parsedURL.Scheme = "http"
	}

	// Block non-HTTP/S schemes to prevent protocol attacks
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendError(ctx, fasthttp.StatusBadRequest, "Only HTTP and HTTPS schemes are allowed")
		return
	}

	targetURL := parsedURL.String()

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(targetURL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("Mozilla/5.0 (URLPreviewBot)")

	if err := httpClient.Do(req, resp); err != nil {
		sendError(ctx, fasthttp.StatusBadGateway, fmt.Sprintf("Fetch failed: %v", err))
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		sendError(ctx, fasthttp.StatusBadGateway, fmt.Sprintf("HTTP %d from target", resp.StatusCode()))
		return
	}

	title, description := extractMetadata(resp.Body())

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(map[string]string{
		"title":       title,
		"description": description,
	})
}

func extractMetadata(htmlData []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlData))
	if err != nil {
		return "", ""
	}

	var title, description string
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		if title != "" && description != "" {
			return
		}
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = getText(n)
				return
			}
			if n.Data == "meta" && description == "" {
				if getAttr(n, "name") == "description" {
					description = getAttr(n, "content")
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
			if title != "" && description != "" {
				break
			}
		}
	}
	visit(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result.WriteString(getText(c))
	}
	return result.String()
}

func getAttr(n *html.Node, key string) string {
	for _, attr := range n.Attr {
		if strings.EqualFold(attr.Key, key) {
			return attr.Val
		}
	}
	return ""
}

func sendError(ctx *fasthttp.RequestCtx, status int, msg string) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(map[string]string{"error": msg})
}

